mapper.select:
SELECT COUNT(*)
FROM TBL_USER_ATTENDANCE
WHERE USER_ID = #{userId}

SELECT USER_ATTENDANCE_DATE
FROM TBL_USER_ATTENDANCE
WHERE USER_ID = #{userId}
  AND USER_ATTENDANCE_DATE >= #{startDate}
  AND USER_ATTENDANCE_DATE < #{endDate}
ORDER BY USER_ATTENDANCE_DATE ASC

SELECT MAX(USER_ATTENDANCE_DATE)
FROM TBL_USER_ATTENDANCE
WHERE USER_ID = #{userId}
